INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('seguranca', 'Bebê pode usar chupeta?', 'Sim! Chupeta até reduz risco de morte súbita. Mas se ele não quer, não força.', 'seguranca', 'seguranca', 'seguranca', 0, 'true');
INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('seguranca', 'Bebê pode dormir na cama comigo?', 'Não é recomendado! Risco de morte súbita. Melhor berço do lado da cama.', 'seguranca', 'seguranca', 'seguranca', 0, 'true');
INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('seguranca', 'Posso deixar bebê sozinho no berço?', 'Sim! Depois de alguns meses, pode deixar sozinho por curtos períodos. Mas sempre de olho!', 'seguranca', 'seguranca', 'seguranca', 0, 'true');
INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('seguranca', 'Qual é a temperatura ideal para o quarto do bebê?', 'Entre 20-22°C é ideal. Nem muito quente, nem muito frio!', 'seguranca', 'seguranca', 'seguranca', 0, 'true');
INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('seguranca', 'Bebê pode usar travesseiro?', 'Não! Antes de 2 anos, nada de travesseiro. Só o colchão firme.', 'seguranca', 'seguranca', 'seguranca', 0, 'true');

